func (s *Server) CopyHandler(c *gin.Context) {
    // 1. Parse JSON request
    var r api.CopyRequest
    if err := c.ShouldBindJSON(&r); errors.Is(err, io.EOF) {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": "missing request body"})
        return
    } else if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // 2. Parse and validate source model name
    src := model.ParseName(r.Source)
    if !src.IsValid() {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("source %q is invalid", r.Source)})
        return
    }
    src, err := getExistingName(src)  // Resolve to exact case/format
    if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // 3. Parse and validate destination model name
    dst := model.ParseName(r.Destination)
    if !dst.IsValid() {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("destination %q is invalid", r.Destination)})
        return
    }
    dst, err = getExistingName(dst)
    if err != nil {
        c.AbortWithStatusJSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // 4. Call the model operation
    if err := CopyModel(src, dst); errors.Is(err, os.ErrNotExist) {
        c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("model %q not found", r.Source)})
    } else if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
    }
}
```

**Key handler patterns:**
1. **Request parsing**: Use `c.ShouldBindJSON(&r)` to deserialize JSON
2. **Model name parsing**: Use `model.ParseName()` to parse model names
3. **Validation**: Check `IsValid()` on model names
4. **Resolution**: Use `getExistingName()` to find the exact stored name (case-sensitive matching)
5. **Error handling**: Return appropriate HTTP status codes with error messages
6. **Model operations**: Call module-level functions like `CopyModel(src, dst)`

---

### 5. COPY MODEL OPERATION (server/images.go, lines 397-434)

**Core implementation:**
```go
func CopyModel(src, dst model.Name) error {
    // Validate both names are fully qualified
    if !dst.IsFullyQualified() {
        return model.Unqualified(dst)
    }
    if !src.IsFullyQualified() {
        return model.Unqualified(src)
    }

    // Early exit if copying to same path
    if src.Filepath() == dst.Filepath() {
        return nil
    }

    // Get manifest directory
    manifests, err := manifest.Path()
    if err != nil {
        return err
    }

    // Create destination directory structure
    dstpath := filepath.Join(manifests, dst.Filepath())
    if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
        return err
    }

    // Open source manifest file
    srcpath := filepath.Join(manifests, src.Filepath())
    srcfile, err := os.Open(srcpath)
    if err != nil {
        return err
    }
    defer srcfile.Close()

    // Create destination manifest file
    dstfile, err := os.Create(dstpath)
    if err != nil {
        return err
    }
    defer dstfile.Close()

    // Copy manifest content
    _, err = io.Copy(dstfile, srcfile)
    return err
}
```

**Key observations:**
- Copies only the **manifest file** (metadata), not the actual model layers
- Model layers are stored separately in `/blobs/` directory and are **shared** between copies
- This is efficient - multiple models can reference the same layers
- Manifests are stored at: `{OLLAMA_MODELS}/manifests/{host}/{namespace}/{model}/{tag}`

